                <div className="si-id" style={{ color: RISK_COLORS[station.rk] || '#3db87a' }}>{station.id}</div>
                <div className="si-n">{station.n}</div>
                <div className="si-r" style={{ color: RISK_COLORS[station.rk] || '#3db87a' }}>
                  {RISK_LABELS[station.rk] || 'Moderate'}
